arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Changed from AddSingleton: .NET 9 enables scope validation by default in
// Development, which prevents resolving scoped IUserService from a singleton.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
builder.Services.AddHttpClient("api")
    // ConfigureHttpMessageHandlerBuilder was removed in .NET 9.
    .ConfigurePrimaryHttpMessageHandler(() =>
        new HttpClientHandler { UseCookies = false });
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
// Kestrel no longer emits Trace-level request-header logs in .NET 9.
// Use the HTTP Logging middleware instead.
builder.Services.AddHttpLogging(options =>
{
    options.LoggingFields = Microsoft.AspNetCore.HttpLogging.HttpLoggingFields.RequestHeaders;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.UseHttpLogging();
app.Run();

